package webui

import "html/template"

// adapterIcon returns an inline SVG icon for a known adapter name.
// Unknown names return empty string (text-only fallback).
func adapterIcon(name string) template.HTML {
	svg, ok := adapterIcons[name]
	if !ok {
		return ""
	}
	return template.HTML(svg)
}

// forgeIcon returns an inline SVG icon for a known forge name.
// Unknown names return empty string (text-only fallback).
func forgeIcon(name string) template.HTML {
	svg, ok := forgeIcons[name]
	if !ok {
		return ""
	}
	return template.HTML(svg)
}

